code.perFrame:
zoom = 1;
rot = 0;
dx = 0;
dy = 0.00001;
sx = 1;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
db=(bass-lbass)*fps*.1;;
lbass=bass;;
avgdb=avgdb*.99+abs(db)*.01;;
dt=(treb-ltreb)*fps*.06;;
ltreb=treb;;
avgdt=avgdt*.99+abs(dt)*.01;;
pitch=(sin(avgdt)+cos(avgdb))*.5+.5;;
avgvol=avgvol*.99+(avgdb+avgdt)*.005;;
monitor=avgvol;;
fc=(30/fps)*avgvol*.01;;
bb=((abs(db)) > (avgdb*6));;
bt=((abs(dt)) > (avgdt*6));;
t1=t1+(avgdb*.01*(1.5-pitch)+bb*db)*fc;;
t2=t2+(avgdt*.01*pitch+bt*dt)*fc;;
t3=t3+abs(db)*.1*avgvol*fc;;
t4=t4+abs(dt)*.1*-avgvol*fc;;
wave_r = 0.5 + 0.5*sin((t1-t4)*2);;
wave_g = 0.4 + 0.4*sin((t3-t2)*2);;
wave_b = -1 + (1-wave_r + 1-wave_g);;
wave_a = min(bass_att,1);;
warp = 0;;
wave_x = wave_x + 0.4*cos(12*t2)*sin(11*t3);;
wave_y = wave_y + 0.4*sin(12*t1)*cos(11*t4);;
ob_r = 1-abs(wave_g);;
ob_b = 1-abs(wave_r);;
ob_g = 1-abs(wave_b);;
ob_a=1;;
ib_a=.5;;
dx_r=avgdt*.001;;
dy_r=avgdb*.001;;
q1=dx_r;;
q2=dy_r;;
q3=t1;;
q4=t2;;
q5=t3;;
q6=t4;;
q7=pitch-.5;;
q8=avgvol;;
wrap=1;;
decay=.99+min(max((avgdt-avgdtb)*.004,-.01),.01);;
cx=.5+.5*sin(q5);;
cy=.5+.5*sin(q6);
